import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"PCB 產業持續監控指標","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/PCB研究/追蹤指標.md","filePath":"Deep32Q知識庫/產業洞察/PCB研究/追蹤指標.md"}'),n={name:"Deep32Q知識庫/產業洞察/PCB研究/追蹤指標.md"};function i(s,t,g,r,x,y){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="pcb-產業持續監控指標" tabindex="-1">PCB 產業持續監控指標 <a class="header-anchor" href="#pcb-產業持續監控指標" aria-label="Permalink to &quot;PCB 產業持續監控指標&quot;">​</a></h1><p><strong>更新日期：2026-05-13</strong><strong>追蹤頻率：週/月/季混合</strong></p><hr><h2 id="一、ai-伺服器板追蹤指標-頻率-週" tabindex="-1">一、AI 伺服器板追蹤指標（頻率：週） <a class="header-anchor" href="#一、ai-伺服器板追蹤指標-頻率-週" aria-label="Permalink to &quot;一、AI 伺服器板追蹤指標（頻率：週）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">#</th><th style="text-align:left;">指標</th><th style="text-align:left;">當前狀態</th><th style="text-align:center;">更新頻率</th><th style="text-align:left;">追蹤對象</th></tr></thead><tbody><tr><td style="text-align:left;">A1</td><td style="text-align:left;">NVIDIA 平台出貨量（HGX/Bianca/GB300）</td><td style="text-align:left;">GB200 量產中，Rubin 開發中</td><td style="text-align:center;">每週</td><td style="text-align:left;">NVIDIA 供應鏈</td></tr><tr><td style="text-align:left;">A2</td><td style="text-align:left;">金像電單季營收與 AI 佔比</td><td style="text-align:left;">2026 Q1: NT$193B, AI ~50%</td><td style="text-align:center;">每週</td><td style="text-align:left;">2368 月營收</td></tr><tr><td style="text-align:left;">A3</td><td style="text-align:left;">伺服器板層數升級趨勢</td><td style="text-align:left;">H100:20–28 → GB200:28–36 → Rubin:&gt;36</td><td style="text-align:center;">每週</td><td style="text-align:left;">各平台規格</td></tr><tr><td style="text-align:left;">A4</td><td style="text-align:left;">CCL 材料損耗等級滲透率（M7/M8/M9）</td><td style="text-align:left;">M7 標配, M8 採用中, M9 驗證完成</td><td style="text-align:center;">每週</td><td style="text-align:left;">台光電/聯茂/台燿</td></tr></tbody></table><hr><h2 id="二、abf-載板追蹤指標-頻率-月" tabindex="-1">二、ABF 載板追蹤指標（頻率：月） <a class="header-anchor" href="#二、abf-載板追蹤指標-頻率-月" aria-label="Permalink to &quot;二、ABF 載板追蹤指標（頻率：月）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">#</th><th style="text-align:left;">指標</th><th style="text-align:left;">當前狀態</th><th style="text-align:center;">更新頻率</th><th style="text-align:left;">追蹤對象</th></tr></thead><tbody><tr><td style="text-align:left;">B1</td><td style="text-align:left;">欣興/南電/景碩單月營收</td><td style="text-align:left;">欣興 2026 Q1: NT$37.45B</td><td style="text-align:center;">每月</td><td style="text-align:left;">3037/8046/3189</td></tr><tr><td style="text-align:left;">B2</td><td style="text-align:left;">ABF 供需狀況</td><td style="text-align:left;">2025 H2–2026 供需轉緊，價格 +5–10%</td><td style="text-align:center;">每月</td><td style="text-align:left;">產業分析</td></tr><tr><td style="text-align:left;">B3</td><td style="text-align:left;">ABF 膜價格（味之素）</td><td style="text-align:left;">預估 2026 H2 漲價 ~30%</td><td style="text-align:center;">每月</td><td style="text-align:left;">味之素公告</td></tr><tr><td style="text-align:left;">B4</td><td style="text-align:left;">新產能開出時程</td><td style="text-align:left;">欣興 NT$34B 擴產中，2027 年產能釋放</td><td style="text-align:center;">每月</td><td style="text-align:left;">各廠法說會</td></tr><tr><td style="text-align:left;">B5</td><td style="text-align:left;">客戶認證進度（NVIDIA/AMD/Intel）</td><td style="text-align:left;">欣興已獲 NVIDIA 認證，其他持續推進中</td><td style="text-align:center;">每月</td><td style="text-align:left;">各廠公告</td></tr></tbody></table><hr><h2 id="三、ccl-產業追蹤指標-頻率-月" tabindex="-1">三、CCL 產業追蹤指標（頻率：月） <a class="header-anchor" href="#三、ccl-產業追蹤指標-頻率-月" aria-label="Permalink to &quot;三、CCL 產業追蹤指標（頻率：月）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">#</th><th style="text-align:left;">指標</th><th style="text-align:left;">當前狀態</th><th style="text-align:center;">更新頻率</th><th style="text-align:left;">追蹤對象</th></tr></thead><tbody><tr><td style="text-align:left;">C1</td><td style="text-align:left;">台光電/聯茂/台燿單月營收</td><td style="text-align:left;">台光電 2026 Q1: NT$330.6B</td><td style="text-align:center;">每月</td><td style="text-align:left;">2383/6213/6274</td></tr><tr><td style="text-align:left;">C2</td><td style="text-align:left;">銅箔/LME 銅價走勢</td><td style="text-align:left;">LME 銅價波動中，HVLP 銅箔溢價較高</td><td style="text-align:center;">每月</td><td style="text-align:left;">LME / 國內報價</td></tr><tr><td style="text-align:left;">C3</td><td style="text-align:left;">M7+/M8 材料滲透率</td><td style="text-align:left;">M7 標配, M8 Google/Meta 採用中</td><td style="text-align:center;">每月</td><td style="text-align:left;">台光電/聯茂/台燿</td></tr><tr><td style="text-align:left;">C4</td><td style="text-align:left;">M9 進度（台光電已完成驗證）</td><td style="text-align:left;">2026–2027 關鍵成長引擎</td><td style="text-align:center;">每月</td><td style="text-align:left;">台光電法說會</td></tr></tbody></table><hr><h2 id="四、總體指標-頻率-季" tabindex="-1">四、總體指標（頻率：季） <a class="header-anchor" href="#四、總體指標-頻率-季" aria-label="Permalink to &quot;四、總體指標（頻率：季）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">#</th><th style="text-align:left;">指標</th><th style="text-align:left;">當前狀態</th><th style="text-align:center;">更新頻率</th><th style="text-align:left;">追蹤對象</th></tr></thead><tbody><tr><td style="text-align:left;">T1</td><td style="text-align:left;">Prismark 全球 PCB 產值預測</td><td style="text-align:left;">2025: US$98–103.6B, 2026: US$105.2B</td><td style="text-align:center;">每季</td><td style="text-align:left;">Prismark 報告</td></tr><tr><td style="text-align:left;">T2</td><td style="text-align:left;">TPCA 台廠產值</td><td style="text-align:left;">2025: NT$9,157B, 2026: NT$1.38–1.5T</td><td style="text-align:center;">每季</td><td style="text-align:left;">TPCA-IEK</td></tr><tr><td style="text-align:left;">T3</td><td style="text-align:left;">台灣 PCB 產業出口數據</td><td style="text-align:left;">持續成長，AI 相關產品佔比提升</td><td style="text-align:center;">每季</td><td style="text-align:left;">經濟部統計處</td></tr><tr><td style="text-align:left;">T4</td><td style="text-align:left;">中國 PCB 產能擴張情況</td><td style="text-align:left;">中低階市場競爭加劇，高階追趕中</td><td style="text-align:center;">每季</td><td style="text-align:left;">digitimes/產業分析</td></tr><tr><td style="text-align:left;">T5</td><td style="text-align:left;">玻璃基板替代進度</td><td style="text-align:left;">Intel/Samsung 2026 年開始量產</td><td style="text-align:center;">每季</td><td style="text-align:left;">Intel/Samsung 公告</td></tr></tbody></table><hr><h2 id="五、leo-衛星追蹤指標-頻率-月" tabindex="-1">五、LEO 衛星追蹤指標（頻率：月） <a class="header-anchor" href="#五、leo-衛星追蹤指標-頻率-月" aria-label="Permalink to &quot;五、LEO 衛星追蹤指標（頻率：月）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">#</th><th style="text-align:left;">指標</th><th style="text-align:left;">當前狀態</th><th style="text-align:center;">更新頻率</th><th style="text-align:left;">追蹤對象</th></tr></thead><tbody><tr><td style="text-align:left;">L1</td><td style="text-align:left;">Starlink 發射數量與衛星部署</td><td style="text-align:left;">2025: &gt;9,000 顆, 2026 V3 衛星</td><td style="text-align:center;">每月</td><td style="text-align:left;">SpaceX 公告</td></tr><tr><td style="text-align:left;">L2</td><td style="text-align:left;">華通 LEO 板營收佔比</td><td style="text-align:left;">2025: ~20–22%, 2026: &gt;26%</td><td style="text-align:center;">每月</td><td style="text-align:left;">華通月營收</td></tr><tr><td style="text-align:left;">L3</td><td style="text-align:left;">Amazon Project Kuiper 進度</td><td style="text-align:left;">已切入華通供應鏈</td><td style="text-align:center;">每月</td><td style="text-align:left;">Amazon 公告</td></tr><tr><td style="text-align:left;">L4</td><td style="text-align:left;">Bastrop 廠產能利用率</td><td style="text-align:left;">2026 目標 &gt;16M kits/年</td><td style="text-align:center;">每月</td><td style="text-align:left;">SpaceX 供應鏈</td></tr></tbody></table><hr><h2 id="六、台股個股追蹤清單-重點關注" tabindex="-1">六、台股個股追蹤清單（重點關注） <a class="header-anchor" href="#六、台股個股追蹤清單-重點關注" aria-label="Permalink to &quot;六、台股個股追蹤清單（重點關注）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">代號</th><th style="text-align:left;">公司</th><th style="text-align:left;">關鍵觀察點</th><th style="text-align:left;">資料來源</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>2368</strong></td><td style="text-align:left;">金像電</td><td style="text-align:left;">AI 佔比、單季營收、NVIDIA 平台出貨</td><td style="text-align:left;">月營收、法說會</td></tr><tr><td style="text-align:left;"><strong>2383</strong></td><td style="text-align:left;">台光電</td><td style="text-align:left;">M7/M8/M9 滲透率、單季營收</td><td style="text-align:left;">月營收、法說會</td></tr><tr><td style="text-align:left;"><strong>2313</strong></td><td style="text-align:left;">華通</td><td style="text-align:left;">LEO 板營收、Starlink 發射進度</td><td style="text-align:left;">月營收、SpaceX 公告</td></tr><tr><td style="text-align:left;"><strong>3037</strong></td><td style="text-align:left;">欣興</td><td style="text-align:left;">ABF 載板產能、資本支出</td><td style="text-align:left;">月營收、法說會</td></tr><tr><td style="text-align:left;"><strong>3044</strong></td><td style="text-align:left;">健鼎</td><td style="text-align:left;">伺服器板佔比、越南新廠進度</td><td style="text-align:left;">月營收、法說會</td></tr><tr><td style="text-align:left;"><strong>8046</strong></td><td style="text-align:left;">南電</td><td style="text-align:left;">ABF 載板佔比、供需狀況</td><td style="text-align:left;">月營收</td></tr><tr><td style="text-align:left;"><strong>6213</strong></td><td style="text-align:left;">聯茂</td><td style="text-align:left;">高速 CCL 市佔、復甦進度</td><td style="text-align:left;">月營收</td></tr><tr><td style="text-align:left;"><strong>6274</strong></td><td style="text-align:left;">台燿</td><td style="text-align:left;">低損耗 CCL 滲透率</td><td style="text-align:left;">月營收</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>Prismark</strong> (2025/2026): 全球 PCB 產值預測</li><li><strong>TPCA-IEK</strong> (2025/10, 2026/05): 台灣 PCB 產值數據</li><li><strong>CTEE 經濟日報</strong> (2026/04, 2026/05): 各公司營收與法人預估</li><li><strong>digitimes</strong> (2026/05): AI 伺服器 PCB 市場分析</li><li><strong>PCMag</strong> (2025): Starlink Bastrop 廠產能數據</li><li><strong>wedbus.com</strong> (2026/01): Intel/Samsung 玻璃基板進度</li><li><strong>fugle.tw</strong> (2026/03): 台光電營收與 M9 進度</li></ol>',23)])])}const o=e(n,[["render",i]]);export{h as __pageData,o as default};
